// Day Counter — calculate next week's number and date range
const config = { start_date: '2026-03-02' };
const start = new Date(config.start_date + 'T00:00:00+01:00');
const now = new Date();
const diffDays = Math.floor((now - start) / 86400000);
const currentWeek = Math.ceil((diffDays + 1) / 7);
const nextWeek = currentWeek + 1;

// Get Mon-Fri of NEXT week
const daysUntilMonday = (8 - now.getDay()) % 7 || 7;
const monday = new Date(now);
monday.setDate(now.getDate() + daysUntilMonday);
const friday = new Date(monday);
friday.setDate(monday.getDate() + 4);

return [{ json: { weekNum: nextWeek, mondayDate: monday.toISOString().split('T')[0], fridayDate: friday.toISOString().split('T')[0] } }];
